:root {
  --card-bg: #ffffff;
  --card-border: #e8e8e8;
  --card-radius: 16px;

  --label-color: #9b8fc2;
  --title-color: #1e1b2e;

  --badge-bg: #d4f0de;
  --badge-text: #1e7a42;

  --stat-value-color: #1e1b2e;
  --stat-unit-color: #9b8fc2;
  --stat-label-color: #aaa9b8;
  --divider-color: #eeecf7;

  --progress-track: #eeecf7;
  --progress-fill: #7c6bc9;
  --progress-label-color: #5a5870;
  --progress-pct-color: #7c6bc9;

  --dot-done: #7c6bc9;
  --dot-skip: #d8d6e8;
  --exercise-name-color: #1e1b2e;
  --exercise-detail-color: #9b8fc2;

  --streak-color: #5a5870;
  --btn-bg: #7c6bc9;
  --btn-text: #ffffff;
  --btn-radius: 8px;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--card-radius);
  padding: 20px;
  width: 420px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.card-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.label {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.08em;
  color: var(--label-color);
  text-transform: uppercase;
}

.title {
  font-size: 22px;
  font-weight: 800;
  color: var(--title-color);
  margin: 0;
  line-height: 1.2;
}

.badge {
  background: var(--badge-bg);
  color: var(--badge-text);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.06em;
  padding: 4px 10px;
  border-radius: 20px;
}

.stats-row {
  display: flex;
  align-items: center;
  background: var(--progress-track);
  border-radius: 12px;
  padding: 14px 0;
}

.stat {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-value {
  font-size: 26px;
  font-weight: 800;
  color: var(--stat-value-color);
  line-height: 1;
}

.stat-unit {
  font-size: 12px;
  font-weight: 600;
  color: var(--stat-unit-color);
}

.stat-label {
  font-size: 11px;
  color: var(--stat-label-color);
  margin-top: 2px;
}

.stat-divider {
  width: 1px;
  height: 36px;
  background: var(--divider-color);
}

.progress-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.progress-label {
  font-size: 13px;
  font-weight: 600;
  color: var(--progress-label-color);
}

.progress-pct {
  font-size: 13px;
  font-weight: 700;
  color: var(--progress-pct-color);
}

.progress-bar {
  height: 8px;
  background: var(--progress-track);
  border-radius: 99px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  width: 74%;
  background: var(--progress-fill);
  border-radius: 99px;
}

.exercise-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.exercise-item {
  display: flex;
  align-items: center;
  gap: 10px;
}

.exercise-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

.dot-done {
  background: var(--dot-done);
}

.dot-skip {
  background: var(--dot-skip);
}

.exercise-name {
  flex: 1;
  font-size: 14px;
  font-weight: 500;
  color: var(--exercise-name-color);
}

.exercise-detail {
  font-size: 13px;
  font-weight: 600;
  color: var(--exercise-detail-color);
}

.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 4px;
  border-top: 1px solid var(--card-border);
}

.streak {
  font-size: 13px;
  font-weight: 600;
  color: var(--streak-color);
}

.btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: var(--btn-radius);
  padding: 8px 18px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
}
